    33→import {
    34→  LazyQuizView,
    35→  LazyFlashcardsView,
    36→  LazyMindmapsView,
    37→  LazySummariesView,
    38→  LazyHomeworkHelpView,
    39→  LazyCalendarView,
    40→  LazyHTMLSnippetsView,
    41→} from '@/components/education';
    42→import { CharacterChatView } from '@/components/conversation';
    43→import { LazySettingsView } from '@/components/settings';
