    57→  melissa: { name: 'Melissa', avatar: '/avatars/melissa.jpg' },
    58→  roberto: { name: 'Roberto', avatar: '/avatars/roberto.png' },
    59→  chiara: { name: 'Chiara', avatar: '/avatars/chiara.png' },
    60→  andrea: { name: 'Andrea', avatar: '/avatars/andrea.png' },
    61→  favij: { name: 'Favij', avatar: '/avatars/favij.jpg' },
    62→} as const;
    63→
    64→const BUDDY_INFO = {
    65→  mario: { name: 'Mario', avatar: '/avatars/mario.jpg' },
    66→  noemi: { name: 'Noemi', avatar: '/avatars/noemi.png' },
    67→  enea: { name: 'Enea', avatar: '/avatars/enea.png' },
    68→  bruno: { name: 'Bruno', avatar: '/avatars/bruno.png' },
    69→  sofia: { name: 'Sofia', avatar: '/avatars/sofia.png' },
    70→} as const;
    71→
    72→export default function Home() {
    73→  const router = useRouter();
    74→  const { hasCompletedOnboarding, isHydrated, hydrateFromApi } = useOnboardingStore();
    75→
    76→  // Hydrate onboarding state from DB on mount
    77→  useEffect(() => {
    78→    hydrateFromApi();
    79→  }, [hydrateFromApi]);
    80→
    81→  // Redirect to welcome if onboarding not completed (only after hydration)
    82→  useEffect(() => {
    83→    if (isHydrated && !hasCompletedOnboarding) {
    84→      router.push('/welcome');
    85→    }
    86→  }, [isHydrated, hasCompletedOnboarding, router]);
    87→
    88→  // Start with Maestri as the first view
