    90→  const [sidebarOpen, setSidebarOpen] = useState(true);
    91→
    92→  // Maestro session state
    93→  const [selectedMaestro, setSelectedMaestro] = useState<Maestro | null>(null);
    94→  const [maestroSessionMode, setMaestroSessionMode] = useState<MaestroSessionMode>('voice');
    95→  const [maestroSessionKey, setMaestroSessionKey] = useState(0);
    96→
    97→  const { xp, level, streak, totalStudyMinutes, sessionsThisWeek, questionsAsked } = useProgressStore();
    98→  const { studentProfile } = useSettingsStore();
    99→  const { hasNewInsights, markAsViewed } = useParentInsightsIndicator();
   100→  const { focusMode } = useUIStore();
   101→  const {
   102→    activeCharacter,
   103→    conversationsByCharacter,
   104→    endConversationWithSummary,
   105→    isActive: isConversationActive
   106→  } = useConversationFlowStore();
   107→
   108→  // Handler to close active conversation before navigating to a different view
   109→  const handleViewChange = async (newView: View) => {
   110→    // If there's an active conversation, close it first
   111→    if (isConversationActive && activeCharacter) {
   112→      const characterConvo = conversationsByCharacter[activeCharacter.id];
   113→      if (characterConvo?.conversationId) {
   114→        const userId = sessionStorage.getItem('convergio-user-id');
   115→        if (userId) {
   116→          try {
   117→            await endConversationWithSummary(characterConvo.conversationId, userId);
   118→          } catch (error) {
   119→            console.error('Failed to close conversation:', error);
   120→          }
   121→        }
   122→      }
   123→    }
   124→    setCurrentView(newView);
   125→  };
   126→
   127→  // Don't render main app until hydration is done and onboarding is completed
   128→  if (!isHydrated || !hasCompletedOnboarding) {
   129→    return null;
   130→  }
   131→
   132→  // XP calculations
   133→  const XP_PER_LEVEL = [0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000];
   134→  const currentLevelXP = XP_PER_LEVEL[level - 1] || 0;
   135→  const nextLevelXP = XP_PER_LEVEL[level] || XP_PER_LEVEL[XP_PER_LEVEL.length - 1];
   136→  const xpInLevel = xp - currentLevelXP;
   137→  const xpNeeded = nextLevelXP - currentLevelXP;
   138→  const progressPercent = Math.min(100, (xpInLevel / xpNeeded) * 100);
   139→
   140→  // Format study time
   141→  const hours = Math.floor(totalStudyMinutes / 60);
   142→  const minutes = totalStudyMinutes % 60;
   143→  const studyTimeStr = hours > 0 ? `${hours}h${minutes}m` : `${minutes}m`;
   144→
   145→  // Get selected coach and buddy from preferences (with defaults)
   146→  const selectedCoach = studentProfile?.preferredCoach || 'melissa';
   147→  const selectedBuddy = studentProfile?.preferredBuddy || 'mario';
   148→  const coachInfo = COACH_INFO[selectedCoach];
   149→  const buddyInfo = BUDDY_INFO[selectedBuddy];
   150→
   151→  const navItems = [
   152→    { id: 'coach' as const, label: coachInfo.name, icon: Sparkles, isChat: true, avatar: coachInfo.avatar },
   153→    { id: 'buddy' as const, label: buddyInfo.name, icon: Heart, isChat: true, avatar: buddyInfo.avatar },
   154→    { id: 'maestri' as const, label: 'Professori', icon: GraduationCap },
   155→    { id: 'quiz' as const, label: 'Quiz', icon: Brain },
   156→    { id: 'flashcards' as const, label: 'Flashcards', icon: BookOpen },
   157→    { id: 'mindmaps' as const, label: 'Mappe Mentali', icon: Network },
   158→    { id: 'summaries' as const, label: 'Riassunti', icon: FileText },
   159→    { id: 'homework' as const, label: 'Materiali', icon: Target },
   160→    { id: 'calendar' as const, label: 'Calendario', icon: Calendar },
   161→    { id: 'demos' as const, label: 'Demo', icon: Brain },
   162→    { id: 'progress' as const, label: 'Progressi', icon: Trophy },
   163→    { id: 'genitori' as const, label: 'Genitori', icon: Users },
   164→    { id: 'settings' as const, label: 'Impostazioni', icon: Settings },
   165→  ];
   166→
   167→  return (
   168→    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-950">
   169→      {/* Unified Header Bar */}
   170→      <header
   171→        className={cn(
   172→          'fixed top-0 right-0 h-14 z-50 flex items-center justify-between px-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200/50 dark:border-slate-700/50 transition-all duration-300',
   173→          sidebarOpen ? 'left-64' : 'left-20'
   174→        )}
   175→      >
   176→        {/* Level + XP Progress */}
   177→        <div className="flex items-center gap-3 min-w-[200px]">
   178→          <div className="w-8 h-8 rounded-full bg-accent-themed flex items-center justify-center flex-shrink-0">
   179→            <Trophy className="w-4 h-4 text-white" />
   180→          </div>
   181→          <div className="flex-1 min-w-0">
   182→            <div className="flex items-baseline gap-2 text-sm">
   183→              <span className="font-bold text-slate-900 dark:text-white">Lv.{level}</span>
   184→              <span className="text-xs text-slate-500">{xpInLevel}/{xpNeeded} XP</span>
   185→            </div>
   186→            <div className="h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden mt-0.5 w-32">
   187→              <motion.div
