   189→                initial={{ width: 0 }}
   190→                animate={{ width: `${progressPercent}%` }}
   191→                transition={{ duration: 0.5 }}
   192→              />
   193→            </div>
   194→          </div>
   195→        </div>
   196→
   197→        {/* Quick Stats */}
   198→        <div className="flex items-center gap-4 text-sm">
   199→          <div className="flex items-center gap-1.5" title="Streak">
   200→            <Flame className={cn("w-4 h-4", streak.current > 0 ? "text-orange-500" : "text-slate-400")} />
   201→            <span className={cn("font-semibold", streak.current > 0 ? "text-orange-500" : "text-slate-500")}>
   202→              {streak.current}
   203→            </span>
   204→          </div>
   205→
   206→          <div className="flex items-center gap-1.5" title="Sessioni questa settimana">
   207→            <BookOpen className="w-4 h-4 text-accent-themed" />
   208→            <span className="font-semibold text-slate-700 dark:text-slate-300">{sessionsThisWeek}</span>
   209→          </div>
   210→
   211→          <div className="flex items-center gap-1.5" title="Tempo di studio">
   212→            <Clock className="w-4 h-4 text-green-500" />
   213→            <span className="font-semibold text-slate-700 dark:text-slate-300">{studyTimeStr}</span>
   214→          </div>
   215→
   216→          <div className="flex items-center gap-1.5" title="Domande fatte">
   217→            <Star className="w-4 h-4 text-purple-500" />
   218→            <span className="font-semibold text-slate-700 dark:text-slate-300">{questionsAsked}</span>
   219→          </div>
   220→
   221→          {/* Streak bonus badge */}
   222→          {streak.current >= 3 && (
   223→            <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 text-xs font-medium">
   224→              <Flame className="w-3 h-3" />
   225→              +{Math.min(streak.current * 10, 50)}% XP
   226→            </div>
   227→          )}
   228→        </div>
   229→
   230→        {/* Right section: ambient audio + pomodoro + notifications + version */}
   231→        <div className="flex items-center gap-3">
   232→          <AmbientAudioHeaderWidget />
   233→          <PomodoroHeaderWidget />
   234→          <NotificationBell />
   235→          <span className="text-xs text-slate-400 dark:text-slate-500 font-mono">
   236→            v{process.env.APP_VERSION}
   237→          </span>
   238→        </div>
   239→      </header>
   240→
   241→      {/* Sidebar */}
   242→      <aside
   243→        className={cn(
   244→          'fixed top-0 left-0 h-full bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 z-40 transition-all duration-300',
   245→          sidebarOpen ? 'w-64' : 'w-20'
   246→        )}
   247→      >
   248→        {/* Logo - clickable to return home */}
   249→        <div className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800">
   250→          <button
   251→            onClick={() => setCurrentView('maestri')}
   252→            className="flex items-center gap-3 hover:opacity-80 transition-opacity"
   253→            aria-label="Torna alla home"
   254→          >
   255→            <div className="w-9 h-9 rounded-xl overflow-hidden flex-shrink-0">
   256→              <Image
   257→                src="/icon.png"
   258→                alt="Convergio"
   259→                width={36}
   260→                height={36}
   261→                className="w-full h-full object-cover"
   262→              />
   263→            </div>
   264→            {sidebarOpen && (
   265→              <span className="font-bold text-lg text-slate-900 dark:text-white">
   266→                Convergio
   267→              </span>
   268→            )}
   269→          </button>
   270→          <Button
   271→            variant="ghost"
   272→            size="icon-sm"
   273→            onClick={() => setSidebarOpen(!sidebarOpen)}
   274→            className="text-slate-500"
   275→            aria-label={sidebarOpen ? 'Chiudi menu' : 'Apri menu'}
   276→          >
   277→            {sidebarOpen ? <PanelLeftClose className="h-4 w-4" /> : <PanelLeftOpen className="h-4 w-4" />}
   278→          </Button>
   279→        </div>
   280→
   281→        {/* Navigation - with bottom padding for XP bar */}
   282→        <nav className="p-4 space-y-2 overflow-y-auto pb-24" style={{ maxHeight: 'calc(100vh - 120px)' }}>
   283→          {navItems.map((item) => {
   284→            const isChatItem = item.id === 'coach' || item.id === 'buddy';
   285→            const avatarSrc = 'avatar' in item ? item.avatar : null;
   286→
   287→            return (
   288→              <button
   289→                key={item.id}
   290→                onClick={async () => {
   291→                  if (item.id === 'genitori') {
   292→                    markAsViewed();
   293→                    // Close active conversation before navigating away
   294→                    await handleViewChange('genitori');
   295→                    router.push('/parent-dashboard');
   296→                  } else {
   297→                    await handleViewChange(item.id);
   298→                  }
   299→                }}
   300→                className={cn(
   301→                  'w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all',
   302→                  currentView === item.id
   303→                    ? 'bg-accent-themed text-white shadow-lg'
   304→                    : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800',
   305→                  isChatItem && 'relative'
   306→                )}
   307→                style={currentView === item.id ? { boxShadow: '0 10px 15px -3px var(--accent-color, #3b82f6)40' } : undefined}
   308→              >
   309→                {avatarSrc ? (
   310→                  <div className="relative flex-shrink-0">
   311→                    <Image
   312→                      src={avatarSrc}
   313→                      alt={item.label}
   314→                      width={32}
   315→                      height={32}
   316→                      className="w-8 h-8 rounded-full object-cover"
   317→                    />
   318→                    <span className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-400 border-2 border-white dark:border-slate-900 rounded-full" />
   319→                  </div>
   320→                ) : (
   321→                  <div className="relative flex-shrink-0">
   322→                    <item.icon className="h-5 w-5" />
   323→                    {item.id === 'genitori' && hasNewInsights && (
   324→                      <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full animate-pulse" />
   325→                    )}
   326→                  </div>
   327→                )}
   328→                {sidebarOpen && <span className="font-medium">{item.label}</span>}
   329→              </button>
   330→            );
   331→          })}
   332→        </nav>
   333→
   334→        {/* XP Progress */}
   335→        {sidebarOpen && (
   336→          <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   337→            <div className="mb-2 flex justify-between text-sm">
   338→              <span className="text-slate-600 dark:text-slate-400">XP</span>
   339→              <span className="font-medium text-slate-900 dark:text-white">
   340→                {xp.toLocaleString()}
   341→              </span>
   342→            </div>
   343→            <div className="h-2 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden">
   344→              <motion.div
   345→                className="h-full bg-accent-themed"
   346→                initial={{ width: 0 }}
   347→                animate={{ width: `${(xp % 1000) / 10}%` }}
   348→              />
   349→            </div>
   350→          </div>
   351→        )}
   352→      </aside>
   353→
   354→      {/* Main content */}
   355→      <main
   356→        className={cn(
   357→          'min-h-screen transition-all duration-300 p-8 pt-20',
   358→          sidebarOpen ? 'ml-64' : 'ml-20'
   359→        )}
   360→      >
   361→
   362→        {/* View content */}
   363→        <motion.div
   364→          key={currentView}
   365→          initial={{ opacity: 0, y: 20 }}
   366→          animate={{ opacity: 1, y: 0 }}
   367→          transition={{ duration: 0.3 }}
   368→        >
   369→          {currentView === 'coach' && (
   370→            <CharacterChatView characterId={selectedCoach} characterType="coach" />
   371→          )}
   372→
   373→          {currentView === 'buddy' && (
   374→            <CharacterChatView characterId={selectedBuddy} characterType="buddy" />
   375→          )}
   376→
   377→          {currentView === 'maestri' && (
   378→            <MaestriGrid
   379→              onMaestroSelect={(maestro, mode) => {
   380→                setSelectedMaestro(maestro);
   381→                setMaestroSessionMode(mode);
   382→                setMaestroSessionKey(prev => prev + 1);
   383→                setCurrentView('maestro-session');
   384→              }}
   385→            />
   386→          )}
   387→
   388→          {currentView === 'maestro-session' && selectedMaestro && (
   389→            <MaestroSession
   390→              key={`maestro-${selectedMaestro.id}-${maestroSessionKey}`}
   391→              maestro={selectedMaestro}
   392→              onClose={() => setCurrentView('maestri')}
   393→              initialMode={maestroSessionMode}
   394→            />
   395→          )}
   396→
   397→          {currentView === 'quiz' && <LazyQuizView />}
   398→
   399→          {currentView === 'flashcards' && <LazyFlashcardsView />}
   400→
   401→          {currentView === 'mindmaps' && <LazyMindmapsView />}
   402→
   403→          {currentView === 'summaries' && <LazySummariesView />}
   404→
   405→          {currentView === 'homework' && <LazyHomeworkHelpView />}
   406→
   407→          {currentView === 'calendar' && <LazyCalendarView />}
   408→
   409→          {currentView === 'demos' && <LazyHTMLSnippetsView />}
   410→
   411→          {currentView === 'progress' && <LazyProgressView />}
   412→
   413→          {currentView === 'settings' && <LazySettingsView />}
   414→        </motion.div>
   415→      </main>
   416→
   417→      {/* Focus Mode Overlay - renders above everything when active */}
   418→      {focusMode && <FocusToolLayout />}
   419→    </div>
   420→  );
   421→}
