     8→import { Button } from '@/components/ui/button';
     9→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
    10→import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
    11→import {
    12→  Loader2,
    13→  AlertCircle,
    14→  RefreshCw,
    15→  FileJson,
    16→  FileText,
    17→  Shield,
    18→  UserCheck,
    19→  Trash2,
    20→  BookOpen,
    21→  User,
    22→  TrendingUp,
    23→  ArrowLeft,
    24→} from 'lucide-react';
    25→import Link from 'next/link';
    26→import type { StudentInsights, ObservationCategory } from '@/types';
    27→
    28→// Demo user ID - in production this would come from authentication
    29→const DEMO_USER_ID = 'demo-student-1';
    30→
    31→interface ConsentStatus {
    32→  hasProfile: boolean;
    33→  parentConsent: boolean;
    34→  studentConsent: boolean;
    35→  consentDate?: string;
    36→  deletionRequested?: string;
    37→}
    38→
    39→interface ProfileMeta {
    40→  confidenceScore: number;
    41→  lastUpdated: string;
    42→  sessionCount: number;
    43→}
    44→
    45→interface LearningEntry {
    46→  id: string;
    47→  maestroId: string;
    48→  subject: string;
    49→  category: string;
    50→  insight: string;
    51→  confidence: number;
    52→  occurrences: number;
    53→  createdAt: string;
    54→  lastSeen: string;
    55→}
    56→
    57→type PageState = 'loading' | 'no-profile' | 'needs-consent' | 'needs-student-consent' | 'ready' | 'error' | 'deletion-pending';
    58→
    59→export default function ParentDashboardPage() {
    60→  const [pageState, setPageState] = useState<PageState>('loading');
    61→  const [insights, setInsights] = useState<StudentInsights | null>(null);
    62→  const [diaryEntries, setDiaryEntries] = useState<DiaryEntry[]>([]);
    63→  const [meta, setMeta] = useState<ProfileMeta | null>(null);
    64→  const [_consentStatus, setConsentStatus] = useState<ConsentStatus | null>(null);
    65→  const [error, setError] = useState<string | null>(null);
    66→  const [isGenerating, setIsGenerating] = useState(false);
    67→  const [isExporting, setIsExporting] = useState(false);
    68→  const [isDiaryLoading, setIsDiaryLoading] = useState(false);
    69→  const [activeTab, setActiveTab] = useState<'diary' | 'profile' | 'progress'>('diary');
    70→
    71→  // Chat with Maestro state (Issue #63)
    72→  const [chatMaestro, setChatMaestro] = useState<{ id: string; name: string } | null>(null);
    73→
    74→  // Handler for "Parla con Professore" button
    75→  const handleTalkToMaestro = useCallback((maestroId: string, maestroName: string) => {
    76→    setChatMaestro({ id: maestroId, name: maestroName });
    77→  }, []);
    78→
    79→  // Fetch consent status
    80→  const fetchConsentStatus = useCallback(async () => {
    81→    try {
    82→      const response = await fetch(`/api/profile/consent?userId=${DEMO_USER_ID}`);
    83→      const data = await response.json();
    84→      if (data.success) {
    85→        setConsentStatus(data.data);
    86→        return data.data as ConsentStatus;
    87→      }
    88→      return null;
    89→    } catch {
    90→      return null;
    91→    }
    92→  }, []);
    93→
    94→  // Fetch learning entries for diary
    95→  const fetchDiaryEntries = useCallback(async () => {
    96→    setIsDiaryLoading(true);
    97→    try {
    98→      const response = await fetch(`/api/learnings?userId=${DEMO_USER_ID}`);
    99→      const data = await response.json();
   100→
   101→      if (response.ok && data.learnings) {
   102→        // Convert to DiaryEntry format
   103→        const entries: DiaryEntry[] = data.learnings.map((l: LearningEntry) => ({
   104→          id: l.id,
   105→          maestroId: l.maestroId || 'unknown',
   106→          maestroName: getMaestroDisplayName(l.maestroId),
   107→          subject: l.subject || '',
   108→          category: l.category as ObservationCategory,
   109→          observation: l.insight,
   110→          isStrength: l.confidence >= 0.7,
   111→          confidence: l.confidence,
   112→          occurrences: l.occurrences,
   113→          createdAt: new Date(l.createdAt),
   114→          lastSeen: new Date(l.lastSeen),
   115→        }));
   116→
   117→        setDiaryEntries(entries);
   118→      }
   119→    } catch (err) {
   120→      console.error('Failed to fetch diary entries:', err);
   121→    } finally {
   122→      setIsDiaryLoading(false);
   123→    }
   124→  }, []);
   125→
   126→  // Helper to get Maestro display name
   127→  const getMaestroDisplayName = (maestroId: string | null): string => {
   128→    if (!maestroId) return 'Professore';
   129→    const names: Record<string, string> = {
   130→      leonardo: 'Leonardo',
   131→      galileo: 'Galileo',
   132→      curie: 'Marie Curie',
   133→      cicerone: 'Cicerone',
   134→      lovelace: 'Ada Lovelace',
   135→      smith: 'Adam Smith',
   136→      shakespeare: 'Shakespeare',
   137→      humboldt: 'Humboldt',
   138→      erodoto: 'Erodoto',
   139→      manzoni: 'Manzoni',
   140→      euclide: 'Euclide',
   141→      mozart: 'Mozart',
   142→      socrate: 'Socrate',
   143→      ippocrate: 'Ippocrate',
   144→      feynman: 'Feynman',
   145→      darwin: 'Darwin',
   146→      chris: 'Chris',
   147→    };
   148→    return names[maestroId.toLowerCase()] || maestroId;
   149→  };
   150→
   151→  // Fetch profile data
   152→  const fetchProfile = useCallback(async () => {
   153→    try {
   154→      const response = await fetch(`/api/profile?userId=${DEMO_USER_ID}`);
   155→      const data = await response.json();
   156→
   157→      if (response.ok && data.success) {
   158→        // Convert date strings to Date objects
   159→        const profileData = data.data;
   160→        profileData.lastUpdated = new Date(profileData.lastUpdated);
   161→        profileData.strengths = profileData.strengths.map((s: { createdAt: string }) => ({
   162→          ...s,
   163→          createdAt: new Date(s.createdAt),
   164→        }));
   165→        profileData.growthAreas = profileData.growthAreas.map((g: { createdAt: string }) => ({
   166→          ...g,
   167→          createdAt: new Date(g.createdAt),
   168→        }));
   169→
   170→        setInsights(profileData);
   171→        setMeta(data.meta);
   172→        return true;
   173→      }
   174→
   175→      if (response.status === 403 && data.requiresConsent) {
   176→        return 'needs-consent';
   177→      }
   178→
   179→      if (response.status === 404) {
   180→        return 'no-profile';
   181→      }
   182→
   183→      throw new Error(data.error || 'Failed to fetch profile');
   184→    } catch (err) {
   185→      throw err;
   186→    }
   187→  }, []);
   188→
   189→  // Initial load
   190→  useEffect(() => {
   191→    const load = async () => {
   192→      setPageState('loading');
   193→      setError(null);
   194→
   195→      try {
   196→        // First check consent status
   197→        const consent = await fetchConsentStatus();
   198→
   199→        if (consent?.deletionRequested) {
   200→          setPageState('deletion-pending');
   201→          return;
   202→        }
   203→
   204→        if (!consent?.hasProfile) {
   205→          setPageState('no-profile');
   206→          return;
   207→        }
   208→
   209→        if (!consent?.parentConsent) {
   210→          setPageState('needs-consent');
   211→          return;
   212→        }
   213→
   214→        // Parent consented but student hasn't
   215→        if (consent?.parentConsent && !consent?.studentConsent) {
   216→          setPageState('needs-student-consent');
   217→          // Still load data - parent can view but with reminder
   218→        }
   219→
   220→        // Fetch profile and diary entries in parallel
   221→        const [result] = await Promise.all([
   222→          fetchProfile(),
   223→          fetchDiaryEntries(),
   224→        ]);
   225→
   226→        if (result === 'needs-consent') {
   227→          setPageState('needs-consent');
   228→        } else if (result === 'no-profile') {
   229→          setPageState('no-profile');
   230→        } else {
   231→          setPageState('ready');
   232→        }
   233→      } catch (err) {
   234→        setError(err instanceof Error ? err.message : 'Unknown error');
   235→        setPageState('error');
   236→      }
   237→    };
   238→
   239→    load();
   240→  }, [fetchConsentStatus, fetchProfile, fetchDiaryEntries]);
   241→
   242→  // Generate profile from learning data
   243→  const handleGenerateProfile = async () => {
   244→    setIsGenerating(true);
   245→    setError(null);
   246→
   247→    try {
   248→      const response = await fetch('/api/profile/generate', {
   249→        method: 'POST',
   250→        headers: { 'Content-Type': 'application/json' },
   251→        body: JSON.stringify({ userId: DEMO_USER_ID, forceRegenerate: true }),
   252→      });
   253→
   254→      const data = await response.json();
   255→
   256→      if (!response.ok) {
   257→        throw new Error(data.message || data.error || 'Failed to generate profile');
   258→      }
   259→
   260→      // Refetch profile and diary after generation
   261→      await Promise.all([fetchProfile(), fetchDiaryEntries()]);
   262→      setPageState('ready');
   263→    } catch (err) {
   264→      setError(err instanceof Error ? err.message : 'Failed to generate profile');
   265→    } finally {
   266→      setIsGenerating(false);
   267→    }
   268→  };
   269→
   270→  // Record consent
   271→  const handleGiveConsent = async () => {
   272→    try {
   273→      const response = await fetch('/api/profile/consent', {
   274→        method: 'POST',
   275→        headers: { 'Content-Type': 'application/json' },
   276→        body: JSON.stringify({
   277→          userId: DEMO_USER_ID,
   278→          parentConsent: true,
   279→          studentConsent: true,
   280→        }),
   281→      });
   282→
   283→      const data = await response.json();
