    32→import type { ObservationCategory } from '@/types';
    33→
    34→/**
    35→ * Diary entry from a Maestro's perspective
    36→ */
    37→export interface DiaryEntry {
    38→  id: string;
    39→  maestroId: string;
    40→  maestroName: string;
    41→  subject: string;
    42→  category: ObservationCategory;
    43→  observation: string;
