    49→}
    50→
    51→interface TeacherDiaryProps {
    52→  entries: DiaryEntry[];
    53→  studentName: string;
    54→  isLoading?: boolean;
    55→  onTalkToMaestro?: (maestroId: string, maestroName: string) => void;
    56→}
    57→
    58→// Italian labels for observation categories
    59→const CATEGORY_LABELS: Record<ObservationCategory, string> = {
    60→  logical_reasoning: 'Ragionamento Logico',
    61→  mathematical_intuition: 'Intuizione Matematica',
    62→  critical_thinking: 'Pensiero Critico',
    63→  study_method: 'Metodo di Studio',
    64→  verbal_expression: 'Espressione Verbale',
    65→  linguistic_ability: 'Abilita Linguistiche',
    66→  creativity: 'Creativita',
    67→  artistic_sensitivity: 'Sensibilita Artistica',
    68→  scientific_curiosity: 'Curiosita Scientifica',
    69→  experimental_approach: 'Approccio Sperimentale',
    70→  spatial_memory: 'Memoria Spaziale',
    71→  historical_understanding: 'Comprensione Storica',
    72→  philosophical_depth: 'Profondita Filosofica',
    73→  physical_awareness: 'Consapevolezza Corporea',
    74→  environmental_awareness: 'Consapevolezza Ambientale',
    75→  narrative_skill: 'Abilita Narrative',
    76→  collaborative_spirit: 'Spirito Collaborativo',
    77→};
    78→
    79→/**
    80→ * TeacherDiary - Diario dei Professori
    81→ *
    82→ * Shows chronological observations from Maestri with suggestions for parents.
    83→ * Part of Issue #57: Parent Dashboard improvements.
    84→ */
    85→export function TeacherDiary({ entries, studentName, isLoading, onTalkToMaestro }: TeacherDiaryProps) {
    86→  const [selectedMaestro, setSelectedMaestro] = useState<string>('all');
    87→  const [selectedSubject, setSelectedSubject] = useState<string>('all');
    88→  const [selectedPeriod, setSelectedPeriod] = useState<string>('all');
    89→  const [searchQuery, setSearchQuery] = useState<string>('');
    90→  const [expandedEntry, setExpandedEntry] = useState<string | null>(null);
    91→
    92→  // Get unique Professori and subjects from entries
    93→  const professoriInEntries = useMemo(() => {
    94→    const unique = new Set(entries.map(e => e.maestroId));
    95→    return Array.from(unique).map(id => {
    96→      const maestro = getMaestroById(id);
    97→      return { id, name: maestro?.displayName || id };
    98→    });
    99→  }, [entries]);
   100→
   101→  const subjectsInEntries = useMemo(() => {
   102→    const unique = new Set(entries.map(e => e.subject).filter(Boolean));
   103→    return Array.from(unique);
   104→  }, [entries]);
   105→
   106→  // Filter entries
   107→  const filteredEntries = useMemo(() => {
   108→    let filtered = [...entries];
   109→
   110→    if (selectedMaestro !== 'all') {
   111→      filtered = filtered.filter(e => e.maestroId === selectedMaestro);
   112→    }
   113→
   114→    if (selectedSubject !== 'all') {
   115→      filtered = filtered.filter(e => e.subject === selectedSubject);
   116→    }
   117→
   118→    if (selectedPeriod !== 'all') {
   119→      const now = new Date();
   120→      const periods: Record<string, number> = {
   121→        'week': 7,
   122→        'month': 30,
   123→        '3months': 90,
   124→      };
   125→      const days = periods[selectedPeriod] || 365;
   126→      const cutoff = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
   127→      filtered = filtered.filter(e => new Date(e.createdAt) >= cutoff);
   128→    }
   129→
   130→    // Text search
   131→    if (searchQuery.trim()) {
   132→      const query = searchQuery.toLowerCase().trim();
   133→      filtered = filtered.filter(e =>
   134→        e.observation.toLowerCase().includes(query) ||
   135→        e.maestroName.toLowerCase().includes(query) ||
   136→        (CATEGORY_LABELS[e.category] || '').toLowerCase().includes(query)
   137→      );
   138→    }
   139→
   140→    // Sort by most recent
   141→    return filtered.sort((a, b) =>
   142→      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
   143→    );
   144→  }, [entries, selectedMaestro, selectedSubject, selectedPeriod, searchQuery]);
   145→
   146→  // Group by date
   147→  const groupedByDate = useMemo(() => {
   148→    const groups: Record<string, DiaryEntry[]> = {};
   149→
   150→    for (const entry of filteredEntries) {
   151→      const date = new Date(entry.createdAt).toLocaleDateString('it-IT', {
   152→        day: 'numeric',
   153→        month: 'long',
   154→        year: 'numeric',
   155→      });
   156→      if (!groups[date]) {
   157→        groups[date] = [];
   158→      }
   159→      groups[date].push(entry);
   160→    }
   161→
   162→    return groups;
   163→  }, [filteredEntries]);
   164→
   165→  if (isLoading) {
   166→    return (
   167→      <Card>
   168→        <CardContent className="p-8 text-center">
   169→          <div className="animate-pulse space-y-4">
   170→            <div className="h-8 bg-slate-200 dark:bg-slate-700 rounded w-1/2 mx-auto" />
   171→            <div className="h-24 bg-slate-200 dark:bg-slate-700 rounded" />
   172→            <div className="h-24 bg-slate-200 dark:bg-slate-700 rounded" />
   173→          </div>
   174→        </CardContent>
   175→      </Card>
   176→    );
   177→  }
   178→
   179→  return (
   180→    <div className="space-y-6">
   181→      {/* Header */}
   182→      <Card className="bg-gradient-to-r from-indigo-50 to-purple-50 dark:from-indigo-900/20 dark:to-purple-900/20 border-indigo-200 dark:border-indigo-800">
   183→        <CardHeader className="pb-2">
   184→          <CardTitle className="flex items-center gap-3 text-xl">
   185→            <BookOpen className="h-6 w-6 text-indigo-500" />
   186→            Diario dei Professori
   187→          </CardTitle>
   188→          <p className="text-slate-600 dark:text-slate-400 text-sm">
   189→            Osservazioni e suggerimenti dei Professori su {studentName}
   190→          </p>
   191→        </CardHeader>
   192→        <CardContent>
   193→          {/* Search and Filters */}
   194→          <div className="mt-2 space-y-4">
   195→            {/* Search input */}
   196→            <div className="relative">
   197→              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
   198→              <input
   199→                type="text"
   200→                value={searchQuery}
   201→                onChange={(e) => setSearchQuery(e.target.value)}
   202→                placeholder="Cerca nelle osservazioni..."
   203→                className="w-full pl-10 pr-10 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
   204→              />
   205→              {searchQuery && (
   206→                <button
   207→                  onClick={() => setSearchQuery('')}
   208→                  className="absolute right-3 top-1/2 -translate-y-1/2 p-0.5 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700"
   209→                  aria-label="Cancella ricerca"
   210→                >
   211→                  <X className="h-4 w-4 text-slate-400" />
   212→                </button>
   213→              )}
   214→            </div>
   215→
   216→            {/* Filters */}
   217→            <div>
   218→              <div className="flex items-center gap-2 mb-3">
   219→                <Filter className="h-4 w-4 text-slate-500" />
   220→                <span className="text-sm text-slate-600 dark:text-slate-400">Filtri:</span>
   221→              </div>
   222→
   223→              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
   224→              <Select value={selectedMaestro} onValueChange={setSelectedMaestro}>
   225→                <SelectTrigger className="w-full h-9">
   226→                  <SelectValue placeholder="Tutti i Professori" />
   227→                </SelectTrigger>
   228→                <SelectContent>
   229→                  <SelectItem value="all">Tutti i Professori</SelectItem>
   230→                  {professoriInEntries.map(m => (
   231→                    <SelectItem key={m.id} value={m.id}>{m.name}</SelectItem>
   232→                  ))}
   233→                </SelectContent>
   234→              </Select>
   235→
   236→              <Select value={selectedSubject} onValueChange={setSelectedSubject}>
   237→                <SelectTrigger className="w-full h-9">
   238→                  <SelectValue placeholder="Tutte le materie" />
   239→                </SelectTrigger>
   240→                <SelectContent>
   241→                  <SelectItem value="all">Tutte le materie</SelectItem>
   242→                  {subjectsInEntries.map(s => (
   243→                    <SelectItem key={s} value={s}>
   244→                      {SUBJECT_NAMES[s] || getMaestroSubject(s) || s}
   245→                    </SelectItem>
   246→                  ))}
   247→                </SelectContent>
   248→              </Select>
   249→
   250→              <Select value={selectedPeriod} onValueChange={setSelectedPeriod}>
   251→                <SelectTrigger className="w-full h-9">
   252→                  <SelectValue placeholder="Periodo" />
   253→                </SelectTrigger>
   254→                <SelectContent>
   255→                  <SelectItem value="all">Tutto</SelectItem>
   256→                  <SelectItem value="week">Ultima settimana</SelectItem>
   257→                  <SelectItem value="month">Ultimo mese</SelectItem>
   258→                  <SelectItem value="3months">Ultimi 3 mesi</SelectItem>
   259→                </SelectContent>
   260→              </Select>
   261→            </div>
   262→            </div>
   263→          </div>
   264→        </CardContent>
   265→      </Card>
   266→
   267→      {/* Entries grouped by date */}
   268→      {Object.keys(groupedByDate).length === 0 ? (
   269→        <Card>
   270→          <CardContent className="p-8 text-center">
   271→            <MessageCircle className="h-12 w-12 text-slate-300 mx-auto mb-4" />
   272→            <h3 className="font-semibold text-slate-700 dark:text-slate-300 mb-2">
   273→              Nessuna osservazione ancora
   274→            </h3>
   275→            <p className="text-sm text-slate-500">
