   277→            </p>
   278→          </CardContent>
   279→        </Card>
   280→      ) : (
   281→        <div className="space-y-6">
   282→          {Object.entries(groupedByDate).map(([date, dateEntries]) => (
   283→            <div key={date} className="space-y-3">
   284→              {/* Date header */}
   285→              <div className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400">
   286→                <Calendar className="h-4 w-4" />
