   292→              <div className="space-y-3">
   293→                <AnimatePresence>
   294→                  {dateEntries.map((entry, idx) => (
   295→                    <DiaryEntryCard
   296→                      key={entry.id}
   297→                      entry={entry}
   298→                      isExpanded={expandedEntry === entry.id}
   299→                      onToggle={() => setExpandedEntry(
