   301→                      )}
   302→                      onTalkToMaestro={onTalkToMaestro}
   303→                      delay={idx * 0.05}
   304→                    />
   305→                  ))}
   306→                </AnimatePresence>
   307→              </div>
   308→            </div>
   309→          ))}
   310→        </div>
   311→      )}
   312→    </div>
   313→  );
   314→}
