   316→/**
   317→ * Individual diary entry card
   318→ */
   319→function DiaryEntryCard({
   320→  entry,
   321→  isExpanded,
   322→  onToggle,
   323→  onTalkToMaestro,
   324→  delay = 0,
   325→}: {
   326→  entry: DiaryEntry;
   327→  isExpanded: boolean;
   328→  onToggle: () => void;
   329→  onTalkToMaestro?: (maestroId: string, maestroName: string) => void;
   330→  delay?: number;
   331→}) {
   332→  const maestro = getMaestroById(entry.maestroId);
   333→  const suggestion = getParentSuggestion(entry.category);
   334→  const subjectName = SUBJECT_NAMES[entry.subject] || getMaestroSubject(entry.maestroId) || entry.subject;
   335→
   336→  return (
   337→    <motion.div
   338→      initial={{ opacity: 0, y: 10 }}
   339→      animate={{ opacity: 1, y: 0 }}
   340→      transition={{ delay }}
   341→    >
   342→      <Card className={cn(
   343→        'overflow-hidden transition-all duration-200',
   344→        entry.isStrength
   345→          ? 'border-amber-200 dark:border-amber-800'
   346→          : 'border-blue-200 dark:border-blue-800'
   347→      )}>
   348→        <CardContent className="p-0">
   349→          {/* Header with Maestro info */}
   350→          <div
   351→            className={cn(
   352→              'p-4 cursor-pointer',
   353→              entry.isStrength
   354→                ? 'bg-gradient-to-r from-amber-50 to-orange-50 dark:from-amber-900/20 dark:to-orange-900/20'
   355→                : 'bg-gradient-to-r from-blue-50 to-indigo-50 dark:from-blue-900/20 dark:to-indigo-900/20'
   356→            )}
   357→            onClick={onToggle}
   358→          >
   359→            <div className="flex items-start gap-4">
   360→              {/* Maestro avatar */}
