                <div className="p-4 bg-white dark:bg-slate-800 border-t border-slate-200 dark:border-slate-700">
                  <div className="flex items-start gap-3">
                    <div className="p-2 rounded-lg bg-yellow-100 dark:bg-yellow-900/30">
                      <Lightbulb className="w-5 h-5 text-yellow-600" />
                    </div>
                    <div className="flex-1 space-y-3">
                      <h5 className="font-semibold text-slate-800 dark:text-slate-200">
                        Suggerimenti per i genitori
                      </h5>

                      <div className="space-y-2 text-sm">
                        <div className="p-3 rounded-lg bg-slate-50 dark:bg-slate-900/50">
                          <p className="font-medium text-slate-700 dark:text-slate-300 mb-1">
                            Attivita a casa:
                          </p>
                          <p className="text-slate-600 dark:text-slate-400">
                            {suggestion.homeActivity}
                          </p>
                        </div>

                        <div className="p-3 rounded-lg bg-slate-50 dark:bg-slate-900/50">
                          <p className="font-medium text-slate-700 dark:text-slate-300 mb-1">
                            Come comunicare:
                          </p>
                          <p className="text-slate-600 dark:text-slate-400">
                            {suggestion.communicationTip}
                          </p>
                        </div>

                        <div className="p-3 rounded-lg bg-slate-50 dark:bg-slate-900/50">
                          <p className="font-medium text-slate-700 dark:text-slate-300 mb-1">
                            Ambiente di studio:
                          </p>
                          <p className="text-slate-600 dark:text-slate-400">
                            {suggestion.environmentTip}
                          </p>
                        </div>
                      </div>

                      {/* Talk to Maestro button - Issue #63 */}
                      {onTalkToMaestro && (
                        <div className="mt-4 pt-4 border-t border-slate-200 dark:border-slate-700">
                          <Button
                            onClick={(e) => {
                              e.stopPropagation();
                              onTalkToMaestro(entry.maestroId, maestro?.displayName || entry.maestroName);
                            }}
                            className="w-full sm:w-auto bg-indigo-600 hover:bg-indigo-700 text-white"
                          >
                            <Phone className="w-4 h-4 mr-2" />
                            Parla con {maestro?.displayName || entry.maestroName}
                          </Button>
                          <p className="text-xs text-slate-500 mt-2">
                            Avvia una conversazione diretta con il Professore per discutere dei progressi.
                          </p>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </CardContent>
      </Card>
    </motion.div>
  );
}

